import{av as a,o as i,c as s,aR as e,bv as n}from"./chunks/framework.BlZS6pWm.js";const F=JSON.parse('{"title":"在 jenkins 中添加参数化构建","description":"","frontmatter":{},"headers":[],"relativePath":"other/jenkins-plugin-git-params.md","filePath":"other/jenkins-plugin-git-params.md","lastUpdated":1716254632000}'),t={name:"other/jenkins-plugin-git-params.md"},l=e('<h1 id="在-jenkins-中添加参数化构建" tabindex="-1">在 jenkins 中添加参数化构建 <a class="header-anchor" href="#在-jenkins-中添加参数化构建" aria-label="Permalink to &quot;在 jenkins 中添加参数化构建&quot;">​</a></h1><p>在之前的文章中，我们介绍了如何安装 Jenkins 并使用其构建 Vue.js 项目。然而，有时候我们希望构建不同的分支，而不是固定于一个特定的分支。 为了实现这个目标，我们可以使用 Jenkins 插件 - Git Parameter。这个插件允许我们在构建过程中动态地选择 Git 仓库中的分支，使得构建过程更加灵活。</p><h2 id="步骤一-安装-git-parameter-插件" tabindex="-1">步骤一：安装 Git Parameter 插件 <a class="header-anchor" href="#步骤一-安装-git-parameter-插件" aria-label="Permalink to &quot;步骤一：安装 Git Parameter 插件&quot;">​</a></h2><p>首先，确保你已经在 Jenkins 中安装了 Git Parameter 插件。如果尚未安装，请按照以下步骤进行：</p><ol><li><p>登录 Jenkins 控制台。</p></li><li><p>转到“Manage Jenkins” &gt; “Manage Plugins” &gt; “Available”选项卡。</p></li><li><p>在搜索框中输入 “Git Parameter” 查找插件。</p></li><li><p>找到 Git Parameter 插件并选中它。</p></li><li><p>单击“Install without restart”按钮安装插件。</p></li></ol><h2 id="步骤二-配置参数化构建" tabindex="-1">步骤二：配置参数化构建 <a class="header-anchor" href="#步骤二-配置参数化构建" aria-label="Permalink to &quot;步骤二：配置参数化构建&quot;">​</a></h2><p>现在，我们将配置一个新的 Jenkins Job，并添加 Git Parameter 以实现参数化构建。</p><ol><li><p>在 Jenkins 控制台，单击“New Item”创建一个新的 Freestyle 项目。</p></li><li><p>在项目配置页面中，找到“General”部分，勾选“This project is parameterized”。</p></li><li><p>单击“Add Parameter”并选择“Git Parameter”。</p></li><li><p>在 “Name” 字段中输入参数名称，例如 “branch”。</p></li><li><p>在“Parameter Type”中选择 “branch”.</p></li></ol><p><img src="'+n+`" alt="Alt text"></p><h2 id="步骤三-配置构建脚本" tabindex="-1">步骤三：配置构建脚本 <a class="header-anchor" href="#步骤三-配置构建脚本" aria-label="Permalink to &quot;步骤三：配置构建脚本&quot;">​</a></h2><p>在构建脚本中，你可以使用<code>\${branch}</code>这样的变量来引用 Git Parameter 中定义的分支参数。例如，你可以在构建步骤中使用以下命令：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 清理工作空间</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clean</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fdx</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 拉取指定分支</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${branch}</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> \${branch}</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在此添加你的构建步骤</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><h2 id="步骤四-保存并构建" tabindex="-1">步骤四：保存并构建 <a class="header-anchor" href="#步骤四-保存并构建" aria-label="Permalink to &quot;步骤四：保存并构建&quot;">​</a></h2><p>保存项目配置后，你可以触发一次构建。在构建过程中，Jenkins 将提示选择分支名称，这个分支名称将作为参数传递给构建脚本。</p><p>通过这种方式，你就成功地实现了参数化构建，并使用 Git Parameter 插件动态选择要构建的分支。这对于具有多个分支的项目以及需要按需构建不同分支的情况非常有用。</p><p>通过上述步骤，你可以方便地扩展你的 Jenkins 构建，实现更加灵活和可定制的构建流程。希望这篇博客能帮助你更好地使用 Git Parameter 插件进行参数化构建。</p>`,16),p=[l];function r(h,k,o,d,c,g){return i(),s("div",null,p)}const u=a(t,[["render",r]]);export{F as __pageData,u as default};
